import React, { useState } from 'react';

interface CheckoutProps {
  onCheckout: () => void;
}

const Checkout: React.FC<CheckoutProps> = ({ onCheckout }) => {
  const [step, setStep] = useState(1);

  const handleNextStep = () => {
    if (step < 3) {
      setStep(step + 1);
    } else {
      onCheckout();
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-md p-6">
      <h2 className="text-xl font-semibold mb-4">Checkout</h2>
      {step === 1 && <div>Shipping Information Form</div>}
      {step === 2 && <div>Payment Options Form</div>}
      {step === 3 && <div>Order Review</div>}
      <button
        onClick={handleNextStep}
        className="mt-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
      >
        {step < 3 ? 'Next' : 'Place Order'}
      </button>
    </div>
  );
};

export default Checkout;

